"""Convert a JSONPath expression to a JSON schema that guarantees
the generated JSON document contains the specified path.

Supported JSONPath syntax
─────────────────────────
  $                   → root object
  .key  or ['key']    → child member access
  [n]                 → array index access  (integer literal)
  [*]                 → wildcard array element
  ..key               → recursive descent  (converted to a schema that
                        requires *key* at the top level – deeper matches
                        are allowed by ``additionalProperties: true``)

The generated schema is intentionally *minimal*: it only enforces that
the path exists in the output structure.  Every intermediate object
allows additional properties and every intermediate array allows
additional items so the model is free to populate the rest of the JSON.

Example
───────
>>> json_path_to_json_schema("$.store.book[*].author")
{
  "type": "object",
  "properties": {
    "store": {
      "type": "object",
      "properties": {
        "book": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "author": {}
            },
            "required": ["author"]
          }
        }
      },
      "required": ["book"]
    }
  },
  "required": ["store"]
}
"""

import json
import logging
import re
from typing import Any, Dict, List, Tuple

logger = logging.getLogger(__name__)

# ---------------------------------------------------------------------------
# Tiny JSONPath tokenizer
# ---------------------------------------------------------------------------

# Token types
_TOK_ROOT = "root"  # $
_TOK_DOT_CHILD = "dot_child"  # .key
_TOK_BRACKET_CHILD = "bracket_child"  # ['key']
_TOK_ARRAY_INDEX = "array_index"  # [0]
_TOK_ARRAY_WILDCARD = "array_wildcard"  # [*]
_TOK_RECURSIVE = "recursive"  # ..key

_TOKEN_RE = re.compile(
    r"""
    (?P<root>\$)                         # root
    |(?P<recursive>\.\.(?P<rkey>\w+))    # recursive descent  ..key
    |(?P<dot_child>\.(?P<dkey>\w+))      # dot child          .key
    |(?P<bracket_child>\['(?P<bkey>[^']+)'\])   # bracket child ['key']
    |(?P<array_wildcard>\[\*\])          # array wildcard     [*]
    |(?P<array_index>\[(?P<idx>\d+)\])   # array index        [n]
    """,
    re.VERBOSE,
)


def _tokenize(path: str) -> List[Tuple[str, str]]:
    """Return a list of (token_type, value) pairs."""
    tokens: List[Tuple[str, str]] = []
    pos = 0
    for m in _TOKEN_RE.finditer(path):
        if m.start() != pos:
            bad = path[pos : m.start()]
            raise ValueError(
                f"Unexpected characters {bad!r} at position {pos} in JSONPath {path!r}"
            )
        pos = m.end()
        if m.group("root") is not None:
            tokens.append((_TOK_ROOT, "$"))
        elif m.group("recursive") is not None:
            tokens.append((_TOK_RECURSIVE, m.group("rkey")))
        elif m.group("dot_child") is not None:
            tokens.append((_TOK_DOT_CHILD, m.group("dkey")))
        elif m.group("bracket_child") is not None:
            tokens.append((_TOK_BRACKET_CHILD, m.group("bkey")))
        elif m.group("array_wildcard") is not None:
            tokens.append((_TOK_ARRAY_WILDCARD, "*"))
        elif m.group("array_index") is not None:
            tokens.append((_TOK_ARRAY_INDEX, m.group("idx")))
    if pos != len(path):
        raise ValueError(
            f"Unexpected trailing characters {path[pos:]!r} in JSONPath {path!r}"
        )
    return tokens


# ---------------------------------------------------------------------------
# Schema builder
# ---------------------------------------------------------------------------


def _build_leaf() -> Dict[str, Any]:
    """Schema for the leaf value – unconstrained."""
    return {}


def _wrap_in_object(key: str, inner: Dict[str, Any]) -> Dict[str, Any]:
    """Wrap *inner* as a required property named *key* inside an object."""
    schema: Dict[str, Any] = {
        "type": "object",
        "properties": {key: inner},
        "required": [key],
    }
    return schema


def _wrap_in_array(inner: Dict[str, Any], *, min_items: int = 1) -> Dict[str, Any]:
    """Wrap *inner* as the items schema of an array."""
    schema: Dict[str, Any] = {
        "type": "array",
        "items": inner,
    }
    if min_items > 0:
        schema["minItems"] = min_items
    return schema


def json_path_to_json_schema(path: str) -> Dict[str, Any]:
    """Convert a JSONPath expression to an equivalent JSON Schema.

    The schema guarantees that any conforming JSON document will contain
    the path described by *path*.

    Raises ``ValueError`` for unsupported or malformed expressions.
    """
    tokens = _tokenize(path)

    if not tokens:
        raise ValueError("Empty JSONPath expression")
    if tokens[0][0] != _TOK_ROOT:
        raise ValueError(f"JSONPath must start with '$', got {path!r}")

    # Build inside-out: start with the leaf and wrap upward.
    schema = _build_leaf()

    # Walk tokens in reverse (skip root '$').
    for tok_type, tok_value in reversed(tokens[1:]):
        if tok_type in (_TOK_DOT_CHILD, _TOK_BRACKET_CHILD, _TOK_RECURSIVE):
            schema = _wrap_in_object(tok_value, schema)
        elif tok_type == _TOK_ARRAY_WILDCARD:
            schema = _wrap_in_array(schema, min_items=1)
        elif tok_type == _TOK_ARRAY_INDEX:
            idx = int(tok_value)
            # For a specific index [n], we need at least n+1 items.
            schema = _wrap_in_array(schema, min_items=idx + 1)
        else:
            raise ValueError(f"Unsupported token type {tok_type!r} in JSONPath")

    # The root '$' always corresponds to the outermost object/array –
    # which we have already built.  If the path is just '$', return a
    # permissive object schema.
    if len(tokens) == 1:
        schema = {"type": "object"}

    return schema


def json_path_to_json_schema_str(path: str) -> str:
    """Convenience wrapper: return the schema as a compact JSON string."""
    return json.dumps(json_path_to_json_schema(path), separators=(",", ":"))

